Similar question: https://leetcode.com/problems/minimum-time-to-complete-trips/
Solution to Q1. 

```
class Solution {
public:
    long long minimumTime(vector<int>& time, int totalTrips) {
        long long maxTime = 0, minTime = 0, ansTime = 0;
        int minVal = time[0];
        for(int i = 1; i < time.size(); i++)
            minVal = min(minVal, time[i]);
        maxTime = (long long) minVal * totalTrips;
        ansTime = maxTime;
        while (minTime <= maxTime){
            long long medTime = (minTime + maxTime)/2;
            long long totalTripsPossible = 0;
            for(int i = 0; i < time.size(); i++){
                if(time[i] == 0)
                    continue;
                totalTripsPossible += medTime/time[i];
            }
            if(totalTripsPossible >= totalTrips){
                //it is possible that with less time also we can make totalTrips
                ansTime = medTime;
                maxTime = medTime - 1;
            }else{
                minTime = medTime + 1;
            }
        }
        return ansTime;

    }
};

